const toggler=document.getElementById("toggler"),menu=document.getElementById("menu");function closeMenu(){menu.classList.remove("is-open"),toggler.classList.remove("fa-xmark"),toggler.classList.add("fa-bars")}toggler.addEventListener("click",()=>{const e=menu.classList.toggle("menu--is-open");toggler.classList.toggle("fa-bars",!e),toggler.classList.toggle("fa-xmark",e)}),document.querySelectorAll(".menu__listing a").forEach(e=>{e.addEventListener("click",closeMenu)});